/// Trait for handling Bucket domain events
///
/// All handler methods receive the event sequence number for tracking
/// which events have been processed by the projector.
#[async_trait]
pub trait BucketEventHandler: Send + Sync {
    /// Handle entity created event
    async fn on_created(&self, event: BucketCreatedEvent, sequence: i64) -> Result<()>;
    /// Handle entity updated event
    async fn on_updated(&self, event: BucketUpdatedEvent, sequence: i64) -> Result<()>;
    /// Handle entity deleted event
    async fn on_deleted(&self, event: BucketDeletedEvent, sequence: i64) -> Result<()>;
}

