/// Projector that updates Bucket projection from events
pub struct BucketProjector<R: BucketProjectionRepository> {
    repository: Arc<R>,
}

impl<R: BucketProjectionRepository> BucketProjector<R> {
    /// Create a new projector
    pub fn new(repository: Arc<R>) -> Self {
        Self { repository }
    }

    /// Rebuild all projections from event history
    pub async fn rebuild(&self) -> Result<u64> {
        self.repository.rebuild_all().await
    }

    /// Process a stored event from the event store
    ///
    /// This method dispatches the event to the appropriate handler based on event type.
    /// Returns Ok(true) if the event was processed, Ok(false) if it was skipped.
    pub async fn process_stored_event(&self, event: &crate::infrastructure::event_store::StoredEvent) -> Result<bool>
    where
        Self: BucketEventHandler,
    {
        let sequence = event.sequence;

        match event.event_type.as_str() {
            "BucketCreatedEvent" => {
                let created: BucketCreatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_created(created, sequence).await?;
                Ok(true)
            }
            "BucketUpdatedEvent" => {
                let updated: BucketUpdatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_updated(updated, sequence).await?;
                Ok(true)
            }
            "BucketDeletedEvent" => {
                let deleted: BucketDeletedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_deleted(deleted, sequence).await?;
                Ok(true)
            }
            _ => Ok(false), // Event type not handled by this projector
        }
    }
}

#[async_trait]
impl<R: BucketProjectionRepository> BucketEventHandler for BucketProjector<R> {

    async fn on_created(&self, event: BucketCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = BucketProjection::new(
            event.id,
            event.name,
            event.slug,
            event.description,
            event.owner_id,
            event.bucket_type,
            event.status,
            event.storage_backend,
            event.root_path,
            event.file_count,
            event.total_size_bytes,
            event.max_file_size,
            event.allowed_mime_types,
            event.auto_delete_after_days,
            event.enable_cdn,
            event.enable_versioning,
            event.enable_deduplication,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: BucketUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.name = event.name;
            projection.slug = event.slug;
            projection.description = event.description;
            projection.owner_id = event.owner_id;
            projection.bucket_type = event.bucket_type;
            projection.status = event.status;
            projection.storage_backend = event.storage_backend;
            projection.root_path = event.root_path;
            projection.file_count = event.file_count;
            projection.total_size_bytes = event.total_size_bytes;
            projection.max_file_size = event.max_file_size;
            projection.allowed_mime_types = event.allowed_mime_types;
            projection.auto_delete_after_days = event.auto_delete_after_days;
            projection.enable_cdn = event.enable_cdn;
            projection.enable_versioning = event.enable_versioning;
            projection.enable_deduplication = event.enable_deduplication;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: BucketDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

